using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<TicketModelTrainer>();

var app = builder.Build();

// Train model at startup and log evaluation metrics
var trainer = app.Services.GetRequiredService<TicketModelTrainer>();
trainer.TrainAndSave();

// Register thread-safe pooled prediction engine from the trained model
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the app with the prediction pool registered
builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<TicketModelTrainer>();
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip"));

app = builder.Build();

// Train model on this fresh build's trainer
var trainerFinal = app.Services.GetRequiredService<TicketModelTrainer>();
trainerFinal.TrainAndSave();

app.MapControllers();
app.Run();

