arguments.new_str:
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly string[] _labelNames;

    public TicketController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        IWebHostEnvironment env)
    {
        _predictionPool = predictionPool;

        // Extract label ordering from the trained model's schema
        var mlContext = new MLContext();
        var modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
        var model = mlContext.Model.Load(modelPath, out _);
        var outputSchema = model.GetOutputSchema(SchemaDefinition.Create(typeof(TicketData)));
        var labelColumn = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetSlotNames(ref slotNames);
        _labelNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var scores = _labelNames
            .Zip(prediction.Score)
            .ToDictionary(pair => pair.First, pair => pair.Second);

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Scores = scores
        });
    }
}

